// K-means iteration using OpenMP (translated from OpenCL kmeansOCL)
int kmeansOCL(float **feature,    
              int n_features,
              int n_points,
              int n_clusters,
              int *membership,
              float **clusters,
              int *new_centers_len,
              float **new_centers)	
{
    int delta = 0;
    int i, j;
    int *membership_old;

    // Save old membership values
    membership_old = (int*) malloc(n_points * sizeof(int));
    for (i = 0; i < n_points; i++) {
        membership_old[i] = membership[i];
    }

    // Reset new_centers
    for (i = 0; i < n_clusters; i++) {
        for (j = 0; j < n_features; j++) {
            new_centers[i][j] = 0.0;
        }
        new_centers_len[i] = 0;
    }

    // Run parallel kmeans kernel
    kmeans_kernel_c(feature[0], clusters[0], membership, n_points, n_clusters, n_features);

    // Update cluster centers
    for (i = 0; i < n_points; i++)
    {
        int cluster_id = membership[i];
        new_centers_len[cluster_id]++;
        if (membership[i] != membership_old[i])
        {
            delta++;
        }
        for (j = 0; j < n_features; j++)
        {
            new_centers[cluster_id][j] += feature[i][j];
        }
    }

    free(membership_old);
    return delta;
}

// K-means clustering using OpenMP (translated from OpenCL version)
float** kmeans_clustering(float **feature,    
                          int nfeatures,
                          int npoints,
                          int nclusters,
                          float threshold,
                          int *membership) 
{    
    int i, j, n = 0;				
    int loop = 0, temp;
    int *new_centers_len;	
    float delta;				
    float **clusters;			
    float **new_centers;		
    int *initial;	
    int initial_points;
    int c = 0;

    if (nclusters > npoints)
        nclusters = npoints;

    // Allocate clusters
    clusters = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*) malloc(nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    // Initialize with random points
    initial = (int *) malloc (npoints * sizeof(int));
    for (i = 0; i < npoints; i++)
    {
        initial[i] = i;
    }
    initial_points = npoints;

    for (i = 0; i < nclusters && initial_points >= 0; i++) {
        for (j = 0; j < nfeatures; j++)
            clusters[i][j] = feature[initial[n]][j];	
        temp = initial[n];
        initial[n] = initial[initial_points - 1];
        initial[initial_points - 1] = temp;
        initial_points--;
        n++;
    }

    for (i = 0; i < npoints; i++)
        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));
    new_centers = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*) calloc(nclusters * nfeatures, sizeof(float));
    for (i = 1; i < nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    do {
        delta = 0.0;
        delta = (float) kmeansOCL(feature, nfeatures, npoints, nclusters, membership, clusters, new_centers_len, new_centers);

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];	
                new_centers[i][j] = 0.0;	
            }
            new_centers_len[i] = 0;			
        }	 
        c++;
    } while ((delta > threshold) && (loop++ < 500));	
    printf("iterated %d times\n", c);
    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}

// Cluster function using OpenMP (translated from OpenCL version)
int cluster(int npoints,				
            int nfeatures,				
            float **features,			                  
            int min_nclusters,			
            int max_nclusters,
            float threshold,				
            int *best_nclusters,		
            float ***cluster_centres,		
            float *min_rmse,				
            int isRMSE,				
            int nloops)
{    
    int nclusters;							
    int index = 0;						
    int rmse;							
    int *membership;						
    float **tmp_cluster_centres;			
    int i;
    float min_rmse_ref = FLT_MAX;

    membership = (int*) malloc(npoints * sizeof(int));

    for(nclusters = min_nclusters; nclusters <= max_nclusters; nclusters++)
    {
        if (nclusters > npoints) break;	

        allocate(npoints, nfeatures, nclusters, features);

        for(i = 0; i < nloops; i++)
        {
            tmp_cluster_centres = kmeans_clustering(features, nfeatures, npoints, nclusters, threshold, membership);

            if (*cluster_centres) {
                free((*cluster_centres)[0]);
                free(*cluster_centres);
            }
            *cluster_centres = tmp_cluster_centres;

            if(isRMSE)
            {
                rmse = rms_err(features, nfeatures, npoints, tmp_cluster_centres, nclusters);

                if(rmse < min_rmse_ref){
                    min_rmse_ref = rmse;			
                    *min_rmse = min_rmse_ref;		
                    *best_nclusters = nclusters;	
                    index = i;						
                }
            }			
        }

        deallocateMemory();							
    }

    free(membership);

    return index;
}
